INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0001-0000-0000-000000000000', '4ea6aa56-31e3-4b33-a7e2-ab2dc6d7723e', 'text', '{"html":"<h3>What a traverse is</h3><p>A <strong>traverse</strong> is a connected sequence of straight lines, called <strong>courses</strong>, whose <strong>lengths</strong> (distances) and <strong>directions</strong> (bearings or azimuths) are measured in the field. By starting at a known point and stepping from course to course, the surveyor can compute the position &mdash; the <strong>coordinates</strong> &mdash; of every traverse station. Traversing is the backbone of most boundary, control, topographic, and construction surveys, because total stations and theodolites measure exactly what a traverse needs: an angle and a distance at each setup.</p><p>The intersection points of successive courses are the <strong>traverse stations</strong> (or angle points). At each station the instrument occupies the point, backsights the previous station, and turns an angle to the next station; the distance to the next station is measured electronically or by tape. The fundamental question for any traverse is whether the field work can be <em>checked</em>. That single question separates the three classical traverse types.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0001-0000-0000-000000000001', '4ea6aa56-31e3-4b33-a7e2-ab2dc6d7723e', 'text', '{"html":"<h3>Open traverse</h3><p>An <strong>open traverse</strong> begins at a known point and ends at a point whose position is <em>not</em> independently known. The line of stations marches out across the ground and simply stops. Because the ending point is unverified, there is <strong>no mathematical check</strong> on the angles or distances: a blunder in any course propagates to the end undetected. Open traverses are common for route surveys &mdash; pipelines, transmission lines, exploratory or preliminary alignments &mdash; where a continuous strip must be located but no convenient closing control exists.</p><p>Because they cannot be checked, open traverses should be used sparingly and only with strong field discipline: repeat angles, double-measure distances, and tie to any available control along the way. A single undetected blunder in an open traverse can render the entire run worthless, with no way to know it from the numbers alone.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0001-0000-0000-000000000002', '4ea6aa56-31e3-4b33-a7e2-ab2dc6d7723e', 'text', '{"html":"<h3>Closed-loop traverse</h3><p>A <strong>closed-loop (polygon) traverse</strong> begins and ends at the <em>same</em> station, tracing a closed figure. Because the start and end coincide, the algebraic sums of the latitudes and of the departures should each be zero, and the interior angles should sum to <strong>(n &minus; 2) &times; 180&deg;</strong>. Any departure from those conditions is the <strong>misclosure</strong>, which is the surveyor''s built-in error check. The closed loop is the standard form for boundary surveys of a single parcel: the perimeter of the tract <em>is</em> the loop.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0001-0000-0000-000000000003', '4ea6aa56-31e3-4b33-a7e2-ab2dc6d7723e', 'text', '{"html":"<h3>Closed-connecting (link) traverse</h3><p>A <strong>closed-connecting</strong> or <strong>link traverse</strong> begins at one point of known coordinates and ends at a <em>different</em> point of known coordinates (often with known azimuths at each end). It does not form a loop, yet it is fully checkable: the computed coordinates of the ending control point should match its published coordinates, and the angular closure can be checked against the known azimuths at the ends. Link traverses are the workhorse of control densification &mdash; for example, running between two NGS or RTK-established control monuments to set new control in between.</p><p>Both closed forms (loop and link) give a misclosure that can be computed and then distributed by an adjustment rule. The open traverse cannot.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0001-0000-0000-000000000004', '4ea6aa56-31e3-4b33-a7e2-ab2dc6d7723e', 'table', '{"headers":["Type","Start / End","Closure check?","Typical use"],"rows":[["Open","Known start, unknown end","No","Preliminary routes, pipelines, exploratory lines"],["Closed-loop (polygon)","Same point start and end","Yes (sums to zero; angles to (n-2)*180)","Boundary of a single parcel"],["Closed-connecting (link)","Known start, different known end","Yes (match end control + azimuths)","Control between two known monuments"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0001-0000-0000-000000000005', '4ea6aa56-31e3-4b33-a7e2-ab2dc6d7723e', 'callout', '{"type":"info","text":"Rule of thumb: if you cannot compute a misclosure, you cannot prove your work. Prefer a closed-loop or link traverse whenever closing control is reasonably available."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0001-0000-0000-000000000006', '4ea6aa56-31e3-4b33-a7e2-ab2dc6d7723e', 'callout', '{"type":"warning","text":"Texas context: A boundary survey must produce a metes-and-bounds description that mathematically closes back to the point of beginning. That is why Texas boundary work is run as a closed-loop traverse; an open traverse cannot support a defensible, closing legal description (see 22 TAC ch. 138 professional standards)."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0001-0000-0000-000000000007', '4ea6aa56-31e3-4b33-a7e2-ab2dc6d7723e', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Open vs. closed-loop vs. closed-connecting (link) traverse geometry."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0001-0000-0000-000000000008', '4ea6aa56-31e3-4b33-a7e2-ab2dc6d7723e', 'key_takeaways', '{"title":"Key Takeaways","items":["A traverse measures the length and direction of each course to locate stations and compute coordinates.","Open traverse: no closure check; use only when no closing control exists and with extra field care.","Closed-loop: starts and ends at the same point; sums of lat/dep should be zero; angles sum to (n-2)*180.","Closed-connecting (link): runs between two known points; checked against the end control and known azimuths.","Only closed traverses can be checked and adjusted, which is why boundary surveys use them."]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0002-0000-0000-000000000000', 'c053d4ff-74a7-4594-a8d1-d0c401307e02', 'text', '{"html":"<h3>Planning the traverse</h3><p>Good traverse data starts before any angle is turned. The surveyor <strong>reconnoiters</strong> the site and chooses station locations that are <strong>intervisible</strong>, on stable ground, safe to occupy, and arranged so the courses form <strong>strong, well-conditioned angles</strong> (avoid very acute or very obtuse angles, which weaken the geometry). Course lengths should be reasonably balanced; one extremely short course adjacent to a long one magnifies centering and pointing error. Each station is monumented &mdash; an iron rod, a nail and shiner, a set spike, or an existing control mark &mdash; and described so it can be recovered.</p><p>The goal of planning is to make the later computation <em>checkable and tight</em>. A traverse that closes on strong geometry with redundant observations is far easier to defend than one rushed through poor station layout.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0002-0000-0000-000000000001', 'c053d4ff-74a7-4594-a8d1-d0c401307e02', 'text', '{"html":"<h3>Carrying direction</h3><p>Three methods carry direction through a traverse. With <strong>interior angles</strong>, the instrument turns the angle inside the polygon at each station; for a closed loop these should sum to (n&minus;2)&times;180&deg;. With <strong>deflection angles</strong>, the instrument measures the angle right or left from the prolongation of the previous course &mdash; common on route surveys; deflection angles sum to 360&deg; for a closed loop. With the <strong>azimuth method</strong>, a reference azimuth is established once and each foresight azimuth is read directly, which is efficient with modern total stations that hold direction.</p><p>Whichever method is used, the surveyor should <strong>close the horizon</strong> (turn angles all the way around the point and verify they sum to 360&deg;) and <strong>repeat angles</strong> by direct and reverse (face-left/face-right) pointings. Repetition averages out pointing error and cancels several instrumental errors (collimation, trunnion-axis, vertical-axis effects).</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0002-0000-0000-000000000002', 'c053d4ff-74a7-4594-a8d1-d0c401307e02', 'text', '{"html":"<h3>Measuring distances</h3><p>Modern traverses measure distances with an <strong>EDM</strong> built into the total station, sighting a prism (reflector). Each distance should be measured at least twice, ideally in both directions, and reduced to a <strong>horizontal distance</strong> using the measured zenith/vertical angle. Corrections include the instrument&ndash;reflector constant (prism offset), atmospheric correction (temperature and pressure affect the modulated light''s velocity), and, for high-order or large-extent work, reduction to the ellipsoid and the grid (scale factor). Slope distances must never be entered into latitude/departure computations &mdash; only horizontal distances.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0002-0000-0000-000000000003', 'c053d4ff-74a7-4594-a8d1-d0c401307e02', 'table', '{"headers":["Direction method","What is measured","Closure condition (loop)"],"rows":[["Interior angles","Angle inside the polygon at each station","Sum = (n-2) x 180 deg"],["Deflection angles","Angle R/L from prolongation of prior course","Algebraic sum = 360 deg"],["Azimuths","Direction of each course from a reference meridian","Return azimuth matches the starting azimuth"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0002-0000-0000-000000000004', 'c053d4ff-74a7-4594-a8d1-d0c401307e02', 'callout', '{"type":"info","text":"Always close the horizon and turn angles by direct and reverse (D&R). Averaging face-left and face-right eliminates collimation and horizontal-axis errors and exposes pointing blunders before you leave the station."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0002-0000-0000-000000000005', 'c053d4ff-74a7-4594-a8d1-d0c401307e02', 'text', '{"html":"<h3>Field notes and quality control</h3><p>The field record must let an independent party reconstruct the survey. For each setup, record the <strong>occupied station</strong>, the <strong>backsight</strong> and <strong>foresight</strong>, the angle(s) and number of repetitions, the slope or horizontal distance with the zenith angle, the height of instrument and reflector, and the temperature/pressure if entered. Note the monument set or found at each station. A disciplined note set, combined with redundant angles and double-measured distances, is what makes the later misclosure small and meaningful rather than a lucky accident.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0002-0000-0000-000000000006', 'c053d4ff-74a7-4594-a8d1-d0c401307e02', 'key_takeaways', '{"title":"Key Takeaways","items":["Choose intervisible, stable stations with strong angles and balanced course lengths.","Carry direction by interior angles, deflection angles, or azimuths; verify the loop angle condition.","Close the horizon and turn angles direct-and-reverse to cancel instrumental errors.","Measure each distance twice and reduce slope to horizontal before computing lat/dep.","Keep complete field notes: occupied/BS/FS, angles, distances, HI/HR, and monuments."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0003-0000-0000-000000000000', '61c4b9a9-e00e-4b80-99da-c15edf192c6e', 'text', '{"html":"<h3>Resolving a course into components</h3><p>To compute coordinates we resolve each course into two rectangular components. The <strong>latitude</strong> of a course is its projection onto the <strong>north&ndash;south</strong> axis; the <strong>departure</strong> is its projection onto the <strong>east&ndash;west</strong> axis. If a course has horizontal distance <em>d</em> and a bearing angle <em>&alpha;</em> measured from the meridian (the north&ndash;south line), then the latitude uses the cosine (it hugs the meridian) and the departure uses the sine (it swings toward east&ndash;west).</p><p>Treat each course as the hypotenuse of a right triangle whose legs are the latitude and the departure. This decomposition is the bridge between field observations (bearings and distances) and the coordinate system in which areas, adjustments, and legal descriptions are computed.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0003-0000-0000-000000000001', '61c4b9a9-e00e-4b80-99da-c15edf192c6e', 'equation', '{"latex":"\\text{Lat} = d\\,\\cos\\alpha \\qquad \\text{Dep} = d\\,\\sin\\alpha","label":"Latitude and departure of a course","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0003-0000-0000-000000000002', '61c4b9a9-e00e-4b80-99da-c15edf192c6e', 'text', '{"html":"<h3>Signs by quadrant</h3><p>The bearing angle &alpha; is always taken as the acute angle from the meridian, so the cosine and sine of &alpha; are positive numbers. The <strong>direction</strong> (sign) comes from the quadrant of the bearing, not from the trig function:</p><ul><li><strong>NE bearing</strong> (N &alpha; E): latitude <strong>+</strong> (north), departure <strong>+</strong> (east).</li><li><strong>SE bearing</strong> (S &alpha; E): latitude <strong>&minus;</strong> (south), departure <strong>+</strong> (east).</li><li><strong>SW bearing</strong> (S &alpha; W): latitude <strong>&minus;</strong> (south), departure <strong>&minus;</strong> (west).</li><li><strong>NW bearing</strong> (N &alpha; W): latitude <strong>+</strong> (north), departure <strong>&minus;</strong> (west).</li></ul><p>If you work in <strong>azimuths</strong> (clockwise from north, 0&ndash;360&deg;) instead, the formulas Lat = d cos(Az) and Dep = d sin(Az) deliver the correct signs automatically, because the azimuth already spans all four quadrants. This is why coordinate-geometry software almost always carries azimuths internally.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0003-0000-0000-000000000003', '61c4b9a9-e00e-4b80-99da-c15edf192c6e', 'table', '{"headers":["Quadrant (bearing)","Latitude sign","Departure sign","Azimuth range"],"rows":[["NE (N a E)","+ (north)","+ (east)","0 to 90 deg"],["SE (S a E)","- (south)","+ (east)","90 to 180 deg"],["SW (S a W)","- (south)","- (west)","180 to 270 deg"],["NW (N a W)","+ (north)","- (west)","270 to 360 deg"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0003-0000-0000-000000000004', '61c4b9a9-e00e-4b80-99da-c15edf192c6e', 'text', '{"html":"<h3>Worked example</h3><p>A course runs <strong>N 35&deg;00'' E for 250.00 ft</strong>. The bearing angle is 35&deg; in the NE quadrant.</p><ul><li>Latitude = 250.00 &times; cos 35&deg; = 250.00 &times; 0.81915 = <strong>+204.79 ft</strong> (north).</li><li>Departure = 250.00 &times; sin 35&deg; = 250.00 &times; 0.57358 = <strong>+143.39 ft</strong> (east).</li></ul><p><strong>Check:</strong> the course length should reappear as the hypotenuse of its components: hypot(204.79, 143.39) = &radic;(204.79&sup2; + 143.39&sup2;) = 250.00 ft. The recombination matching the measured distance confirms the resolution is correct &mdash; a quick, powerful self-check you should run on every course.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0003-0000-0000-000000000005', '61c4b9a9-e00e-4b80-99da-c15edf192c6e', 'equation', '{"latex":"d = \\sqrt{\\text{Lat}^2 + \\text{Dep}^2}","label":"Course length recovered from its components (check)","display":"block"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0003-0000-0000-000000000006', '61c4b9a9-e00e-4b80-99da-c15edf192c6e', 'callout', '{"type":"info","text":"Memory aid: LATitude is the NORTH-south component and uses coSINE... no — latitude uses COSINE; departure (east-west) uses SINE. Because latitude lies along the meridian from which the bearing angle is measured, it ''leads'' with cosine."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0003-0000-0000-000000000007', '61c4b9a9-e00e-4b80-99da-c15edf192c6e', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: A course resolved into latitude (d cos a) and departure (d sin a)."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0003-0000-0000-000000000008', '61c4b9a9-e00e-4b80-99da-c15edf192c6e', 'key_takeaways', '{"title":"Key Takeaways","items":["Lat = d cos(bearing angle); Dep = d sin(bearing angle).","Sign of latitude follows N(+)/S(-); sign of departure follows E(+)/W(-).","Using azimuths (0-360) makes the signs come out automatically.","Check each course: hypot(lat, dep) must equal the measured horizontal distance.","Always use horizontal distances, never slope distances, in these formulas."]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0004-0000-0000-000000000000', '3dd698ce-6ccc-4a03-a8d7-f19a53f40a16', 'text', '{"html":"<h3>Why a closed traverse should sum to zero</h3><p>In a closed-loop traverse you leave a point and return to it. Geometrically, walking the perimeter must bring you back to the same north&ndash;south position and the same east&ndash;west position. Therefore the <strong>algebraic sum of all latitudes</strong> should be zero and the <strong>algebraic sum of all departures</strong> should be zero. Field measurements are never perfect, so the sums come out slightly nonzero. Those small residuals are the <strong>misclosure in latitude</strong> (&Sigma;Lat) and the <strong>misclosure in departure</strong> (&Sigma;Dep). For a link traverse the same idea applies, but the target sums equal the known coordinate differences between the end control points rather than zero.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0004-0000-0000-000000000001', '3dd698ce-6ccc-4a03-a8d7-f19a53f40a16', 'equation', '{"latex":"E_L = \\textstyle\\sum \\text{Lat}, \\quad E_D = \\textstyle\\sum \\text{Dep}, \\quad E = \\sqrt{E_L^2 + E_D^2}","label":"Misclosure in latitude, in departure, and linear (total) misclosure","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0004-0000-0000-000000000002', '3dd698ce-6ccc-4a03-a8d7-f19a53f40a16', 'text', '{"html":"<h3>Linear misclosure</h3><p>The <strong>linear misclosure</strong> <em>E</em> is the straight-line gap between where the traverse computationally ends and where it should end (the point of beginning). Because the latitude and departure misclosures are perpendicular components, <em>E</em> is their hypotenuse: E = hypot(&Sigma;Lat, &Sigma;Dep). A well-run total-station loop of a few hundred feet of perimeter will typically misclose by only a few hundredths of a foot. A misclosure of several tenths of a foot &mdash; or, worse, several feet &mdash; is a red flag for a blunder (a transposed digit, a missed angle, a wrong prism height) that must be hunted down before adjusting.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0004-0000-0000-000000000003', '3dd698ce-6ccc-4a03-a8d7-f19a53f40a16', 'text', '{"html":"<h3>Relative precision (ratio of closure)</h3><p>An absolute misclosure of 0.05 ft means something very different on a 300-ft loop than on a 30,000-ft loop. To make quality comparable across jobs, surveyors express it as a <strong>relative precision</strong>, or <strong>ratio of closure</strong>: the perimeter (total length traversed) divided by the linear misclosure. The result is reduced to the form <strong>1:N</strong>, where <strong>N = round(perimeter / E)</strong>. A ratio of 1:12,000 means the loop misses closure by one part in twelve thousand. Larger N is better. The ratio is dimensionless, so any consistent unit (feet or meters) works as long as perimeter and misclosure share it.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0004-0000-0000-000000000004', '3dd698ce-6ccc-4a03-a8d7-f19a53f40a16', 'equation', '{"latex":"\\text{Relative precision} = \\frac{1}{\\;P / E\\;} = 1 : N, \\quad N = \\operatorname{round}\\!\\left(\\frac{P}{E}\\right)","label":"Ratio of closure (P = perimeter, E = linear misclosure)","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0004-0000-0000-000000000005', '3dd698ce-6ccc-4a03-a8d7-f19a53f40a16', 'table', '{"headers":["Survey type / order","Typical minimum ratio of closure"],"rows":[["Lower-order / rough construction stakeout","1:5,000"],["Ordinary boundary / land survey","1:7,500 to 1:10,000"],["Urban / suburban boundary, higher value","1:10,000 to 1:15,000"],["Control / engineering of higher order","1:20,000 and tighter"]]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0004-0000-0000-000000000006', '3dd698ce-6ccc-4a03-a8d7-f19a53f40a16', 'callout', '{"type":"warning","text":"Texas context: 22 TAC ch. 663 (TBPELS general rules) and the Texas Society of Professional Surveyors'' Manual of Practice set positional-accuracy and closure expectations for boundary surveys. Confirm the controlling standard for the survey category and county before accepting a traverse; a passing ratio does not by itself prove the absence of compensating blunders."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0004-0000-0000-000000000007', '3dd698ce-6ccc-4a03-a8d7-f19a53f40a16', 'callout', '{"type":"info","text":"A good ratio of closure is necessary but not sufficient. Two equal-and-opposite blunders can produce a deceptively small misclosure. Always sanity-check individual courses and angles, not just the final ratio."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0004-0000-0000-000000000008', '3dd698ce-6ccc-4a03-a8d7-f19a53f40a16', 'key_takeaways', '{"title":"Key Takeaways","items":["Misclosure components: E_L = sum of latitudes, E_D = sum of departures (target zero for a loop).","Linear misclosure E = hypot(E_L, E_D).","Ratio of closure = perimeter / E, written 1:N with N = round(P / E); larger N is better.","Compare N against the required standard for the survey class before adjusting.","A passing ratio can still hide compensating blunders; check the individual observations."]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0005-0000-0000-000000000000', '24eb9a48-b37f-4615-ac1b-db880aa3480c', 'text', '{"html":"<h3>The Bowditch assumption</h3><p>Once a misclosure is computed, it must be <strong>distributed</strong> back into the courses so the traverse closes perfectly and coordinates can be assigned. The <strong>compass rule</strong>, also called the <strong>Bowditch rule</strong>, is the most widely used method. It rests on a simple assumption: the precision of the <strong>angle</strong> measurements and the precision of the <strong>distance</strong> measurements are roughly <em>comparable</em>, so accumulated error is proportional to the length of each course. Long courses, having more opportunity to accumulate error, receive proportionally larger corrections; short courses receive smaller ones.</p><p>This assumption fits ordinary total-station boundary traverses well, where angles and EDM distances are both observed to high and similar relative precision. It is the default adjustment for most land surveys.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0005-0000-0000-000000000001', '24eb9a48-b37f-4615-ac1b-db880aa3480c', 'equation', '{"latex":"C_{\\text{Lat},i} = -E_L \\cdot \\frac{d_i}{P}, \\qquad C_{\\text{Dep},i} = -E_D \\cdot \\frac{d_i}{P}","label":"Compass (Bowditch) rule corrections for course i (d_i = length, P = perimeter)","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0005-0000-0000-000000000002', '24eb9a48-b37f-4615-ac1b-db880aa3480c', 'text', '{"html":"<h3>Applying the corrections</h3><p>For each course <em>i</em> of length <em>d<sub>i</sub></em>, the latitude correction is the negative of the latitude misclosure scaled by that course''s share of the perimeter, and likewise for departure. The <strong>negative sign</strong> is essential: the correction removes the misclosure, so it opposes the residual. The <strong>corrected latitude</strong> is the raw latitude plus its correction, and the <strong>corrected departure</strong> is the raw departure plus its correction.</p><p>Because the corrections for all courses sum to &minus;E<sub>L</sub> (and &minus;E<sub>D</sub>), the adjusted latitudes and departures each sum to <strong>zero</strong> for a loop &mdash; the traverse now closes exactly. A standard worked layout adds two columns (correction and adjusted value) beside the raw latitude and departure columns; the bottom of each adjusted column must total zero, which is the proof the arithmetic is right.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0005-0000-0000-000000000003', '24eb9a48-b37f-4615-ac1b-db880aa3480c', 'table', '{"headers":["Course","Length d_i (ft)","Raw Lat (ft)","Lat correction = -E_L*(d_i/P)"],"rows":[["AB","200.00","+150.00","-0.012"],["BC","300.00","-100.00","-0.018"],["CD","250.00","-130.00","-0.015"],["DA","250.00","+80.04","-0.015"],["Sum (P = 1000.00)","1000.00","E_L = +0.060","-0.060 (closes)"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0005-0000-0000-000000000004', '24eb9a48-b37f-4615-ac1b-db880aa3480c', 'callout', '{"type":"info","text":"Sign discipline: the correction is the NEGATIVE of the misclosure share. If the latitudes summed to +0.060 ft (too much north), every latitude correction is negative, pulling the total back to zero."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0005-0000-0000-000000000005', '24eb9a48-b37f-4615-ac1b-db880aa3480c', 'text', '{"html":"<h3>Worked single-course correction</h3><p>Suppose a traverse has departure misclosure E<sub>D</sub> = +0.050 ft over a perimeter P = 1,000.00 ft, and one course is 250.00 ft long. The compass-rule departure correction for that course is:</p><ul><li>C<sub>Dep</sub> = &minus;E<sub>D</sub> &times; (d / P) = &minus;0.050 &times; (250.00 / 1000.00) = &minus;0.050 &times; 0.250 = <strong>&minus;0.0125 ft</strong>.</li></ul><p>So this course''s departure is reduced by about 0.013 ft. Repeating for every course and for both latitude and departure yields a fully adjusted, perfectly closing traverse ready for coordinate computation.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0005-0000-0000-000000000006', '24eb9a48-b37f-4615-ac1b-db880aa3480c', 'callout', '{"type":"warning","text":"Adjustment is not a substitute for good observations. Apply the compass rule only after the ratio of closure passes the required standard. If the misclosure is large, find and fix the blunder before adjusting; spreading a blunder across all courses corrupts otherwise-good data."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0005-0000-0000-000000000007', '24eb9a48-b37f-4615-ac1b-db880aa3480c', 'key_takeaways', '{"title":"Key Takeaways","items":["The compass (Bowditch) rule assumes comparable angle and distance precision; corrections are proportional to course length.","Lat correction = -E_L*(d_i/P); Dep correction = -E_D*(d_i/P).","Add corrections to raw lat/dep to get adjusted values; the negative sign removes the misclosure.","Adjusted latitudes and departures must each sum to zero (loop).","Adjust only after the ratio of closure passes; never spread a blunder."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0006-0000-0000-000000000000', '2e258399-f9ef-432f-a67c-b6e624269e55', 'text', '{"html":"<h3>A different assumption</h3><p>The <strong>transit rule</strong> is a second classical adjustment. Where the compass rule assumes angle and distance precision are <em>comparable</em>, the transit rule assumes the <strong>angles are measured more precisely than the distances</strong>. Under that assumption the error lives mainly in the distances, so the misclosure should be distributed in proportion to the <strong>magnitude of each course''s latitude and departure</strong> &mdash; the very quantities the distance errors most affect &mdash; rather than in proportion to the raw course length.</p><p>Because the corrections follow the components, the transit rule disturbs the computed <strong>bearings</strong> less than the compass rule does. That is the practical signature of an angle-dominant adjustment: hold the directions, push the lengths.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0006-0000-0000-000000000001', '2e258399-f9ef-432f-a67c-b6e624269e55', 'equation', '{"latex":"C_{\\text{Lat},i} = -E_L \\cdot \\frac{|\\text{Lat}_i|}{\\sum |\\text{Lat}|}, \\qquad C_{\\text{Dep},i} = -E_D \\cdot \\frac{|\\text{Dep}_i|}{\\sum |\\text{Dep}|}","label":"Transit rule corrections for course i","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0006-0000-0000-000000000002', '2e258399-f9ef-432f-a67c-b6e624269e55', 'text', '{"html":"<h3>How to apply it</h3><p>The procedure mirrors the compass rule but changes the weighting factor:</p><ul><li>Sum the <strong>absolute values</strong> of all latitudes, &Sigma;|Lat|, and of all departures, &Sigma;|Dep|.</li><li>For each course, the latitude correction is &minus;E<sub>L</sub> times that course''s share of &Sigma;|Lat|, and the departure correction is &minus;E<sub>D</sub> times its share of &Sigma;|Dep|.</li><li>Add the corrections to the raw latitudes and departures; the adjusted columns must each sum to zero.</li></ul><p>Note the latitude correction uses only the latitude totals and the departure correction uses only the departure totals &mdash; the two components are weighted independently, unlike the compass rule where both use the same length fraction.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0006-0000-0000-000000000003', '2e258399-f9ef-432f-a67c-b6e624269e55', 'table', '{"headers":["Aspect","Compass (Bowditch) rule","Transit rule"],"rows":[["Core assumption","Angle and distance precision comparable","Angles more precise than distances"],["Weighting factor","Course length / perimeter","|Lat_i| / sum|Lat| and |Dep_i| / sum|Dep|"],["Effect on bearings","Bearings shift more","Bearings shift less"],["Common use today","Default for boundary traverses","Classical, angle-dominant cases"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0006-0000-0000-000000000004', '2e258399-f9ef-432f-a67c-b6e624269e55', 'callout', '{"type":"info","text":"Choosing a rule: if you trust your angles much more than your distances, the transit rule is theoretically appropriate. With modern total stations both are excellent and comparable, so the compass rule (or a rigorous least-squares adjustment) is the usual choice."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0006-0000-0000-000000000005', '2e258399-f9ef-432f-a67c-b6e624269e55', 'text', '{"html":"<h3>Limitations and modern practice</h3><p>The transit rule has a known weakness: it can behave erratically when a course''s latitude or departure is near zero (a nearly east&ndash;west or nearly north&ndash;south line), because that component contributes almost nothing to the weighting and may receive almost no correction even when it should. For this reason, and because the underlying assumption (angles far better than distances) rarely holds for modern instruments, most software and most surveyors default to the <strong>compass rule</strong> or to a <strong>least-squares adjustment</strong>, which rigorously weights every observation by its own estimated precision. The transit rule remains valuable to understand because it clarifies how an adjustment''s assumptions drive where the error goes.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0006-0000-0000-000000000006', '2e258399-f9ef-432f-a67c-b6e624269e55', 'key_takeaways', '{"title":"Key Takeaways","items":["The transit rule assumes angles are more precise than distances.","Lat correction = -E_L*(|Lat_i|/sum|Lat|); Dep correction = -E_D*(|Dep_i|/sum|Dep|).","It disturbs computed bearings less than the compass rule.","It can misbehave when a course''s latitude or departure is near zero.","Modern practice favors the compass rule or least squares; know the transit rule for context."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0007-0000-0000-000000000000', 'd597ed54-edfa-42b1-97b7-1064d9acc5f1', 'text', '{"html":"<h3>From components to coordinates</h3><p>Once the traverse is adjusted so its latitudes and departures close, computing station coordinates is straightforward bookkeeping. <strong>Northing</strong> accumulates the latitudes; <strong>easting</strong> accumulates the departures. Beginning at the point of beginning with a chosen coordinate, you add each course''s <em>adjusted</em> latitude to the running northing and its adjusted departure to the running easting, station by station, all the way around. The result is a coordinate for every traverse station &mdash; the foundation for plotting, area computation, stakeout, and the legal description.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0007-0000-0000-000000000001', 'd597ed54-edfa-42b1-97b7-1064d9acc5f1', 'equation', '{"latex":"N_{i+1} = N_i + \\text{Lat}_{i}^{\\text{adj}}, \\qquad E_{i+1} = E_i + \\text{Dep}_{i}^{\\text{adj}}","label":"Coordinate forward computation (accumulating adjusted components)","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0007-0000-0000-000000000002', 'd597ed54-edfa-42b1-97b7-1064d9acc5f1', 'text', '{"html":"<h3>Choosing the starting coordinate</h3><p>The starting coordinate may be <strong>assumed</strong> (for an isolated, local survey you might set the point of beginning at N = 5,000.00, E = 5,000.00 to keep every coordinate positive) or it may be a <strong>real, published value</strong> on a recognized datum. For survey-grade Texas work the starting point is normally tied to the <strong>Texas State Plane Coordinate System</strong> on NAD83, so the traverse coordinates are directly compatible with GIS, neighboring surveys, and recorded control. Always use <em>adjusted</em> latitudes and departures, never the raw ones; carrying raw components forward leaves the loop open by the misclosure.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0007-0000-0000-000000000003', 'd597ed54-edfa-42b1-97b7-1064d9acc5f1', 'table', '{"headers":["Station","Adj. Lat (ft)","Adj. Dep (ft)","Northing (ft)","Easting (ft)"],"rows":[["A (POB)","-","-","5000.00","5000.00"],["B","+150.00","+200.00","5150.00","5200.00"],["C","-100.00","+50.00","5050.00","5250.00"],["D","-130.00","-180.00","4920.00","5070.00"],["A (check)","+80.00","-70.00","5000.00","5000.00"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0007-0000-0000-000000000004', 'd597ed54-edfa-42b1-97b7-1064d9acc5f1', 'callout', '{"type":"info","text":"The closure check is built in: after summing all adjusted courses, the recomputed coordinate of the point of beginning must equal its starting coordinate exactly. If it does not, an arithmetic error slipped in after adjustment."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0007-0000-0000-000000000005', 'd597ed54-edfa-42b1-97b7-1064d9acc5f1', 'text', '{"html":"<h3>Worked accumulation</h3><p>Take A as the point of beginning at N = 5,000.00, E = 5,000.00. Course A&rarr;B has adjusted Lat = +150.00 and Dep = +200.00:</p><ul><li>N<sub>B</sub> = 5,000.00 + 150.00 = <strong>5,150.00</strong>; E<sub>B</sub> = 5,000.00 + 200.00 = <strong>5,200.00</strong>.</li></ul><p>Continue with course B&rarr;C (Lat &minus;100.00, Dep +50.00): N<sub>C</sub> = 5,050.00, E<sub>C</sub> = 5,250.00. Proceeding through D and back to A, the accumulated latitudes (+150 &minus;100 &minus;130 +80 = 0) and departures (+200 +50 &minus;180 &minus;70 = 0) return the coordinate to exactly N = 5,000.00, E = 5,000.00 &mdash; confirming a clean, closed, coordinate-bearing traverse.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0007-0000-0000-000000000006', 'd597ed54-edfa-42b1-97b7-1064d9acc5f1', 'callout', '{"type":"warning","text":"Texas context: When tying to the Texas State Plane Coordinate System, remember that grid distances differ from ground distances by the combined (grid x elevation) scale factor. For boundary stakeout you typically work in ground distances and convert; record clearly whether coordinates and distances are grid or ground (TBPELS standards, 22 TAC ch. 663)."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0007-0000-0000-000000000007', 'd597ed54-edfa-42b1-97b7-1064d9acc5f1', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Accumulating adjusted latitudes and departures into station coordinates, closing back on the POB."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0007-0000-0000-000000000008', 'd597ed54-edfa-42b1-97b7-1064d9acc5f1', 'key_takeaways', '{"title":"Key Takeaways","items":["N_{i+1} = N_i + adjusted Lat; E_{i+1} = E_i + adjusted Dep.","Start from an assumed or published (State Plane) coordinate at the POB.","Always carry adjusted (not raw) components forward.","A closed loop must return exactly to its starting coordinate.","Texas survey-grade coordinates use the Texas State Plane Coordinate System (NAD83); track grid vs. ground."]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0008-0000-0000-000000000000', '1085aa13-7c9d-4929-84c8-bc9f7d50448b', 'text', '{"html":"<h3>Putting it all together</h3><p>This lesson ties the module into a single, end-to-end procedure. Given a set of measured courses (bearings and horizontal distances) for a closed-loop traverse, you: (1) compute each course''s <strong>latitude and departure</strong>; (2) sum them to get the <strong>misclosure</strong> and the <strong>ratio of closure</strong>, and verify the ratio meets the required standard; (3) <strong>adjust</strong> the traverse (usually the compass rule) so the components close; (4) accumulate the adjusted components into <strong>station coordinates</strong>; and (5) compute the parcel <strong>area</strong> from those coordinates. Each step has a built-in check, so by the end you have both an answer and the evidence it is correct.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0008-0000-0000-000000000001', '1085aa13-7c9d-4929-84c8-bc9f7d50448b', 'text', '{"html":"<h3>Area by coordinates (the shoelace method)</h3><p>Once you have closed coordinates for every corner, the parcel area follows directly from the <strong>coordinate (shoelace) method</strong>. Taking the corners in order around the perimeter (consistently clockwise or counterclockwise), the area is half the absolute value of the sum of the cross-products x<sub>i</sub>y<sub>i+1</sub> &minus; x<sub>i+1</sub>y<sub>i</sub>. The method is exact for any closed polygon and is the modern replacement for the older double-meridian-distance (DMD) tabulation. It is critical that the traverse be <strong>balanced (adjusted)</strong> first &mdash; an unclosed figure yields an area that includes the misclosure gap and is therefore wrong.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0008-0000-0000-000000000002', '1085aa13-7c9d-4929-84c8-bc9f7d50448b', 'equation', '{"latex":"A = \\frac{1}{2}\\left| \\sum_{i=1}^{n} \\left(x_i\\,y_{i+1} - x_{i+1}\\,y_i\\right) \\right|","label":"Area by coordinates (shoelace formula), indices cyclic","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0008-0000-0000-000000000003', '1085aa13-7c9d-4929-84c8-bc9f7d50448b', 'text', '{"html":"<h3>Worked area example</h3><p>A balanced four-sided parcel has corners (E, N): A(5000, 5000), B(5200, 5150), C(5250, 5050), D(5070, 4920). Form the cross-products around the loop (closing D back to A):</p><ul><li>&Sigma;(x<sub>i</sub>y<sub>i+1</sub>) = (5000&middot;5150)+(5200&middot;5050)+(5250&middot;4920)+(5070&middot;5000)</li><li>&Sigma;(x<sub>i+1</sub>y<sub>i</sub>) = (5200&middot;5000)+(5250&middot;5150)+(5070&middot;5050)+(5000&middot;4920)</li></ul><p>The area is half the absolute difference of those two sums. Dividing the result (in square feet) by 43,560 converts it to acres. Running the numbers gives a clean parcel area &mdash; the deliverable that lands in the legal description as ''containing X acres, more or less.''</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0008-0000-0000-000000000004', '1085aa13-7c9d-4929-84c8-bc9f7d50448b', 'callout', '{"type":"info","text":"Order and direction: keep the corners in strict perimeter order. Traversing clockwise vs. counterclockwise only flips the sign of the summation, which the absolute value removes — so the area magnitude is unaffected."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0008-0000-0000-000000000005', '1085aa13-7c9d-4929-84c8-bc9f7d50448b', 'text', '{"html":"<h3>Practice strategy</h3><p>The dynamic problems attached to this module each isolate one skill: resolving a course into latitude or departure, computing a linear misclosure from small closing errors, converting a misclosure into a ratio of closure, and applying a single compass-rule correction. Work them until each computation is automatic, then chain them on a full traverse. On the SIT/RPLS exams, partial-credit traverse problems reward exactly this disciplined, step-by-step approach: components, closure, ratio, adjustment, coordinates, area &mdash; with a check at every stage.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0008-0000-0000-000000000006', '1085aa13-7c9d-4929-84c8-bc9f7d50448b', 'callout', '{"type":"warning","text":"Common pitfall: computing area before balancing the traverse, or mixing raw and adjusted coordinates. Always balance first, then use only the adjusted (closed) coordinates in the shoelace formula."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0810-0008-0000-0000-000000000007', '1085aa13-7c9d-4929-84c8-bc9f7d50448b', 'key_takeaways', '{"title":"Key Takeaways","items":["Full workflow: lat/dep -> misclosure & ratio -> adjust -> coordinates -> area.","Area by coordinates: A = (1/2)|sum(x_i*y_{i+1} - x_{i+1}*y_i)| on a balanced traverse.","Convert square feet to acres by dividing by 43,560.","Keep corners in perimeter order; clockwise vs. CCW only flips a sign.","Never compute area from an unbalanced traverse or mixed raw/adjusted coordinates."]}'::jsonb, 7);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000001', 'Traverse', 'A connected series of lines (courses) whose lengths and directions are measured to determine the relative positions and coordinates of the traverse stations.', 'Lengths + directions of connected lines.', 'c1000008-0000-0000-0000-000000000008', '4ea6aa56-31e3-4b33-a7e2-ab2dc6d7723e', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000002', 'Open traverse', 'A traverse that starts at a known point and ends at an unverified point, providing no mathematical check on the measurements.', 'No way to compute misclosure.', 'c1000008-0000-0000-0000-000000000008', '4ea6aa56-31e3-4b33-a7e2-ab2dc6d7723e', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000003', 'Closed-loop (polygon) traverse', 'A traverse that begins and ends at the same station, so the sums of latitudes and departures should each be zero and the interior angles should sum to (n-2)*180 degrees.', 'Returns to its start.', 'c1000008-0000-0000-0000-000000000008', '4ea6aa56-31e3-4b33-a7e2-ab2dc6d7723e', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000004', 'Closed-connecting (link) traverse', 'A traverse that begins at one known point and ends at a different known point, checked against the ending control''s coordinates and the known azimuths at the ends.', 'Between two known monuments.', 'c1000008-0000-0000-0000-000000000008', '4ea6aa56-31e3-4b33-a7e2-ab2dc6d7723e', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000005', 'Closing the horizon', 'Turning angles entirely around an occupied station so that the observed angles sum to 360 degrees, providing an on-station check against blunders.', 'All angles around the point sum to 360.', 'c1000008-0000-0000-0000-000000000008', 'c053d4ff-74a7-4594-a8d1-d0c401307e02', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000006', 'Deflection angle', 'The angle measured right or left from the prolongation (extension) of the preceding course to the next course; deflection angles in a closed loop sum to 360 degrees.', 'Turn from the straight-ahead line.', 'c1000008-0000-0000-0000-000000000008', 'c053d4ff-74a7-4594-a8d1-d0c401307e02', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000007', 'Direct and reverse (D&R)', 'Observing an angle on both faces of the instrument (face-left and face-right) and averaging, which cancels collimation and horizontal-axis instrumental errors.', 'Two telescope faces, averaged.', 'c1000008-0000-0000-0000-000000000008', 'c053d4ff-74a7-4594-a8d1-d0c401307e02', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000008', 'Horizontal distance reduction', 'Converting a measured slope distance to its horizontal component using the zenith/vertical angle; only horizontal distances are used in latitude and departure calculations.', 'Slope times sin(zenith).', 'c1000008-0000-0000-0000-000000000008', 'c053d4ff-74a7-4594-a8d1-d0c401307e02', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000009', 'Latitude (of a course)', 'The north-south component of a course, equal to distance x cos(bearing angle); positive to the north, negative to the south.', 'd cos(bearing); N+/S-.', 'c1000008-0000-0000-0000-000000000008', '61c4b9a9-e00e-4b80-99da-c15edf192c6e', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000010', 'Departure (of a course)', 'The east-west component of a course, equal to distance x sin(bearing angle); positive to the east, negative to the west.', 'd sin(bearing); E+/W-.', 'c1000008-0000-0000-0000-000000000008', '61c4b9a9-e00e-4b80-99da-c15edf192c6e', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000011', 'Bearing angle', 'The acute angle a course makes with the meridian (north-south line), measured 0 to 90 degrees from north or south toward east or west; its quadrant supplies the lat/dep signs.', 'Measured from N or S, max 90 deg.', 'c1000008-0000-0000-0000-000000000008', '61c4b9a9-e00e-4b80-99da-c15edf192c6e', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000012', 'Component check', 'Verifying a resolved course by recombining its components: the measured distance must equal sqrt(latitude^2 + departure^2).', 'hypot(lat, dep) = distance.', 'c1000008-0000-0000-0000-000000000008', '61c4b9a9-e00e-4b80-99da-c15edf192c6e', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000013', 'Linear misclosure', 'The straight-line distance between a closed traverse''s computed end point and its true end point, equal to hypot(sum of latitudes, sum of departures).', 'Hypotenuse of the lat and dep errors.', 'c1000008-0000-0000-0000-000000000008', '3dd698ce-6ccc-4a03-a8d7-f19a53f40a16', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000014', 'Ratio of closure (relative precision)', 'A dimensionless measure of traverse quality equal to perimeter divided by linear misclosure, expressed as 1:N where N = round(perimeter / misclosure).', '1 : (P / E).', 'c1000008-0000-0000-0000-000000000008', '3dd698ce-6ccc-4a03-a8d7-f19a53f40a16', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000015', 'Misclosure in latitude / departure', 'The nonzero algebraic sums of the latitudes and departures of a closed-loop traverse, which should ideally be zero; the residuals reveal accumulated measurement error.', 'Sum of lats and sum of deps.', 'c1000008-0000-0000-0000-000000000008', '3dd698ce-6ccc-4a03-a8d7-f19a53f40a16', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000016', 'Perimeter (in closure)', 'The total length of all courses traversed; the numerator of the ratio of closure.', 'Sum of all course distances.', 'c1000008-0000-0000-0000-000000000008', '3dd698ce-6ccc-4a03-a8d7-f19a53f40a16', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000017', 'Compass (Bowditch) rule', 'A traverse adjustment method that distributes the latitude and departure misclosures to each course in proportion to that course''s length, assuming angles and distances are of comparable precision.', 'Correction proportional to course length.', 'c1000008-0000-0000-0000-000000000008', '24eb9a48-b37f-4615-ac1b-db880aa3480c', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000018', 'Latitude correction (compass rule)', 'The amount added to a course''s latitude under the compass rule, equal to -E_L x (course length / perimeter).', '-(lat misclosure)*(d/P).', 'c1000008-0000-0000-0000-000000000008', '24eb9a48-b37f-4615-ac1b-db880aa3480c', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000019', 'Departure correction (compass rule)', 'The amount added to a course''s departure under the compass rule, equal to -E_D x (course length / perimeter).', '-(dep misclosure)*(d/P).', 'c1000008-0000-0000-0000-000000000008', '24eb9a48-b37f-4615-ac1b-db880aa3480c', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000020', 'Adjusted (corrected) latitude', 'The raw latitude of a course plus its computed correction; the adjusted latitudes of a closed loop sum to zero.', 'Raw lat + correction.', 'c1000008-0000-0000-0000-000000000008', '24eb9a48-b37f-4615-ac1b-db880aa3480c', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000021', 'Transit rule', 'A traverse adjustment that distributes the latitude and departure misclosures in proportion to the magnitudes of each course''s latitude and departure, assuming angles are measured more precisely than distances.', 'Weight by |lat| and |dep|, not length.', 'c1000008-0000-0000-0000-000000000008', '2e258399-f9ef-432f-a67c-b6e624269e55', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000022', 'Transit vs. compass rule', 'The compass rule weights corrections by course length (angles and distances comparable); the transit rule weights them by component magnitude (angles more precise), so it changes bearings less.', 'Length vs. component weighting.', 'c1000008-0000-0000-0000-000000000008', '2e258399-f9ef-432f-a67c-b6e624269e55', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000023', 'Transit rule limitation', 'The transit rule can give erratic corrections when a course''s latitude or departure is near zero, and its ''angles far better than distances'' assumption rarely fits modern total stations.', 'Trouble near zero components.', 'c1000008-0000-0000-0000-000000000008', '2e258399-f9ef-432f-a67c-b6e624269e55', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000024', 'Coordinate forward computation', 'Computing each station''s coordinates by adding the adjusted latitude to the running northing and the adjusted departure to the running easting, course by course from the point of beginning.', 'Accumulate adjusted lat/dep.', 'c1000008-0000-0000-0000-000000000008', 'd597ed54-edfa-42b1-97b7-1064d9acc5f1', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000025', 'Northing / Easting', 'The north-south and east-west coordinates of a point; northings accumulate latitudes and eastings accumulate departures along a traverse.', 'N from lats, E from deps.', 'c1000008-0000-0000-0000-000000000008', 'd597ed54-edfa-42b1-97b7-1064d9acc5f1', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000026', 'Texas State Plane Coordinate System', 'The official grid coordinate system (on NAD83) used for survey-grade horizontal positions in Texas, making traverse coordinates compatible with GIS and recorded control.', 'NAD83 grid for Texas.', 'c1000008-0000-0000-0000-000000000008', 'd597ed54-edfa-42b1-97b7-1064d9acc5f1', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000027', 'Grid vs. ground distance', 'Grid distances on a state-plane system differ from measured ground distances by the combined scale factor (grid x elevation factor); surveys must record which is used.', 'Combined scale factor relates them.', 'c1000008-0000-0000-0000-000000000008', 'd597ed54-edfa-42b1-97b7-1064d9acc5f1', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000028', 'Area by coordinates (shoelace)', 'A method to compute a closed polygon''s area as half the absolute value of the sum of cross-products x_i*y_{i+1} - x_{i+1}*y_i, using the balanced traverse coordinates in perimeter order.', 'Half the absolute cross-product sum.', 'c1000008-0000-0000-0000-000000000008', '1085aa13-7c9d-4929-84c8-bc9f7d50448b', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000029', 'Balanced traverse', 'A traverse whose latitudes and departures have been adjusted to close exactly; only a balanced traverse gives a correct coordinate area.', 'Adjusted so it closes.', 'c1000008-0000-0000-0000-000000000008', '1085aa13-7c9d-4929-84c8-bc9f7d50448b', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000030', 'Acre conversion', 'One acre equals 43,560 square feet; divide a square-foot area by 43,560 to express it in acres.', 'sq ft / 43,560.', 'c1000008-0000-0000-0000-000000000008', '1085aa13-7c9d-4929-84c8-bc9f7d50448b', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0840-0000-0000-0000-000000000031', 'Double meridian distance (DMD)', 'A classical tabular method of computing traverse area from latitudes and departures; largely superseded by the coordinate (shoelace) method but mathematically equivalent.', 'Older area method, same result.', 'c1000008-0000-0000-0000-000000000008', '1085aa13-7c9d-4929-84c8-bc9f7d50448b', 'surveying', ARRAY['buildout','module-8']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0830-0000-0000-0000-000000000001', 'Which traverse type provides NO mathematical check on its measurements?', 'multiple_choice', '["Open traverse","Closed-loop traverse","Closed-connecting (link) traverse","Polygon traverse"]'::jsonb, 'Open traverse', 'An open traverse ends at an unverified point, so there is no closure condition to check the angles or distances. Both closed-loop and link traverses can be checked against known geometry/control.', 'easy', 'c1000008-0000-0000-0000-000000000008', '4ea6aa56-31e3-4b33-a7e2-ab2dc6d7723e', ARRAY['buildout','module-8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0830-0000-0000-0000-000000000002', 'A traverse that begins at one known control point and ends at a DIFFERENT known control point is called a:', 'multiple_choice', '["Closed-connecting (link) traverse","Open traverse","Closed-loop traverse","Deflection traverse"]'::jsonb, 'Closed-connecting (link) traverse', 'A link (closed-connecting) traverse runs between two known points and is checked against the ending control''s coordinates and the known azimuths. A closed-loop returns to the same point; an open traverse has no known end.', 'easy', 'c1000008-0000-0000-0000-000000000008', '4ea6aa56-31e3-4b33-a7e2-ab2dc6d7723e', ARRAY['buildout','module-8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0830-0000-0000-0000-000000000003', 'For a closed-loop traverse with n sides, the interior angles should sum to:', 'multiple_choice', '["(n - 2) x 180 degrees","n x 180 degrees","360 degrees regardless of n","(n + 2) x 180 degrees"]'::jsonb, '(n - 2) x 180 degrees', 'The interior angles of any simple n-sided polygon sum to (n-2) x 180 degrees. Deflection angles (a different measure) sum to 360 degrees.', 'medium', 'c1000008-0000-0000-0000-000000000008', '4ea6aa56-31e3-4b33-a7e2-ab2dc6d7723e', ARRAY['buildout','module-8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0830-0000-0000-0000-000000000004', 'Why are angles commonly observed direct and reverse (face-left and face-right) and then averaged?', 'multiple_choice', '["To cancel collimation and horizontal-axis instrumental errors","To convert slope distances to horizontal","To increase the EDM range","To eliminate the need to close the horizon"]'::jsonb, 'To cancel collimation and horizontal-axis instrumental errors', 'Averaging the two faces cancels collimation (line-of-sight) and trunnion/horizontal-axis errors and helps catch pointing blunders. It does nothing for slope reduction or EDM range.', 'medium', 'c1000008-0000-0000-0000-000000000008', 'c053d4ff-74a7-4594-a8d1-d0c401307e02', ARRAY['buildout','module-8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0830-0000-0000-0000-000000000005', 'In a closed-loop traverse, deflection angles should algebraically sum to:', 'multiple_choice', '["360 degrees","(n - 2) x 180 degrees","180 degrees","Zero"]'::jsonb, '360 degrees', 'Deflection angles (turned right/left from the prolongation of the prior course) sum to 360 degrees around a closed loop. Interior angles sum to (n-2) x 180 degrees.', 'medium', 'c1000008-0000-0000-0000-000000000008', 'c053d4ff-74a7-4594-a8d1-d0c401307e02', ARRAY['buildout','module-8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0830-0000-0000-0000-000000000006', 'Slope distances may be entered directly into latitude and departure computations.', 'true_false', '["True","False"]'::jsonb, 'False', 'Only horizontal distances are used in lat/dep computations. Slope distances must first be reduced to horizontal using the zenith/vertical angle.', 'easy', 'c1000008-0000-0000-0000-000000000008', 'c053d4ff-74a7-4594-a8d1-d0c401307e02', ARRAY['buildout','module-8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0830-0000-0000-0000-000000000007', 'The latitude of a course is computed as:', 'multiple_choice', '["distance x cos(bearing angle)","distance x sin(bearing angle)","distance x tan(bearing angle)","distance / cos(bearing angle)"]'::jsonb, 'distance x cos(bearing angle)', 'Latitude (the north-south component) = d cos(alpha); departure (the east-west component) = d sin(alpha), where alpha is the bearing angle from the meridian.', 'easy', 'c1000008-0000-0000-0000-000000000008', '61c4b9a9-e00e-4b80-99da-c15edf192c6e', ARRAY['buildout','module-8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0830-0000-0000-0000-000000000008', 'For a course bearing S 40 degrees W, the signs of its latitude and departure are:', 'multiple_choice', '["Latitude negative, departure negative","Latitude positive, departure positive","Latitude negative, departure positive","Latitude positive, departure negative"]'::jsonb, 'Latitude negative, departure negative', 'South gives a negative latitude and West gives a negative departure. NE = (+,+), SE = (-,+), SW = (-,-), NW = (+,-).', 'medium', 'c1000008-0000-0000-0000-000000000008', '61c4b9a9-e00e-4b80-99da-c15edf192c6e', ARRAY['buildout','module-8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0830-0000-0000-0000-000000000009', 'A course runs N 35 degrees E for 250.00 ft. To the nearest 0.01 ft, its departure is:', 'numeric_input', '[]'::jsonb, '143.39', 'Departure = d sin(alpha) = 250.00 x sin(35 deg) = 250.00 x 0.57358 = 143.39 ft (east, positive).', 'medium', 'c1000008-0000-0000-0000-000000000008', '61c4b9a9-e00e-4b80-99da-c15edf192c6e', ARRAY['buildout','module-8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0830-0000-0000-0000-000000000010', 'The linear misclosure of a closed-loop traverse is computed as:', 'multiple_choice', '["sqrt((sum of latitudes)^2 + (sum of departures)^2)","(sum of latitudes) + (sum of departures)","perimeter / number of courses","(sum of latitudes) x (sum of departures)"]'::jsonb, 'sqrt((sum of latitudes)^2 + (sum of departures)^2)', 'Linear misclosure is the hypotenuse of the latitude and departure misclosures: E = sqrt(E_L^2 + E_D^2) = hypot(sum Lat, sum Dep).', 'easy', 'c1000008-0000-0000-0000-000000000008', '3dd698ce-6ccc-4a03-a8d7-f19a53f40a16', ARRAY['buildout','module-8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0830-0000-0000-0000-000000000011', 'A closed traverse has a perimeter of 2,400.00 ft and a linear misclosure of 0.20 ft. Its ratio of closure (1:N) is approximately:', 'multiple_choice', '["1:12,000","1:480","1:2,400","1:24,000"]'::jsonb, '1:12,000', 'Ratio = perimeter / misclosure = 2400.00 / 0.20 = 12,000, so the relative precision is 1:12,000.', 'medium', 'c1000008-0000-0000-0000-000000000008', '3dd698ce-6ccc-4a03-a8d7-f19a53f40a16', ARRAY['buildout','module-8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0830-0000-0000-0000-000000000012', 'A ratio of closure of 1:5,000 represents BETTER survey precision than 1:15,000.', 'true_false', '["True","False"]'::jsonb, 'False', 'A larger denominator N is better. 1:15,000 misses closure by one part in fifteen thousand, which is more precise than 1:5,000.', 'easy', 'c1000008-0000-0000-0000-000000000008', '3dd698ce-6ccc-4a03-a8d7-f19a53f40a16', ARRAY['buildout','module-8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0830-0000-0000-0000-000000000013', 'A small ratio-of-closure misclosure guarantees there are no blunders in the traverse.', 'true_false', '["True","False"]'::jsonb, 'False', 'Two equal-and-opposite blunders can compensate and produce a deceptively small misclosure. A passing ratio is necessary but not sufficient; check the individual observations.', 'medium', 'c1000008-0000-0000-0000-000000000008', '3dd698ce-6ccc-4a03-a8d7-f19a53f40a16', ARRAY['buildout','module-8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0830-0000-0000-0000-000000000014', 'Under the compass (Bowditch) rule, the correction to a course''s departure is:', 'multiple_choice', '["-E_D x (course length / perimeter)","-E_D x (|Dep_i| / sum|Dep|)","-E_D / number of courses","-E_D x (perimeter / course length)"]'::jsonb, '-E_D x (course length / perimeter)', 'The compass rule distributes the departure misclosure in proportion to course length: correction = -E_D x (d_i / P). Weighting by |Dep_i|/sum|Dep| is the transit rule.', 'medium', 'c1000008-0000-0000-0000-000000000008', '24eb9a48-b37f-4615-ac1b-db880aa3480c', ARRAY['buildout','module-8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0830-0000-0000-0000-000000000015', 'A traverse has a departure misclosure of +0.040 ft over a perimeter of 800.00 ft. The compass-rule departure correction for a 200.00 ft course is:', 'numeric_input', '[]'::jsonb, '-0.010', 'Correction = -E_D x (d/P) = -0.040 x (200.00/800.00) = -0.040 x 0.250 = -0.010 ft.', 'medium', 'c1000008-0000-0000-0000-000000000008', '24eb9a48-b37f-4615-ac1b-db880aa3480c', ARRAY['buildout','module-8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0830-0000-0000-0000-000000000016', 'Under the compass rule, which course receives the LARGEST correction?', 'multiple_choice', '["The longest course","The shortest course","The course with the smallest latitude","Every course receives an equal correction"]'::jsonb, 'The longest course', 'Because the compass rule weights corrections by course length (d_i/P), the longest course gets the largest share of the misclosure.', 'easy', 'c1000008-0000-0000-0000-000000000008', '24eb9a48-b37f-4615-ac1b-db880aa3480c', ARRAY['buildout','module-8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0830-0000-0000-0000-000000000017', 'The transit rule assumes that:', 'multiple_choice', '["Angles are measured more precisely than distances","Distances are measured more precisely than angles","Angle and distance precision are exactly equal","All courses are the same length"]'::jsonb, 'Angles are measured more precisely than distances', 'The transit rule assumes angles are better than distances, so it distributes misclosure by the magnitudes of the latitudes and departures rather than by course length.', 'medium', 'c1000008-0000-0000-0000-000000000008', '2e258399-f9ef-432f-a67c-b6e624269e55', ARRAY['buildout','module-8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0830-0000-0000-0000-000000000018', 'Compared with the compass rule, the transit rule generally disturbs the computed BEARINGS:', 'multiple_choice', '["Less","More","By exactly the same amount","Only for east-west courses"]'::jsonb, 'Less', 'Because the transit rule weights corrections by the latitude/departure components (holding angles), it changes the computed bearings less than the compass rule does.', 'medium', 'c1000008-0000-0000-0000-000000000008', '2e258399-f9ef-432f-a67c-b6e624269e55', ARRAY['buildout','module-8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0830-0000-0000-0000-000000000019', 'Station coordinates are accumulated along a traverse using:', 'multiple_choice', '["N_{i+1} = N_i + adjusted Lat; E_{i+1} = E_i + adjusted Dep","N_{i+1} = N_i + raw Lat; E_{i+1} = E_i + raw Dep","N_{i+1} = N_i x adjusted Lat; E_{i+1} = E_i x adjusted Dep","N_{i+1} = N_i - adjusted Dep; E_{i+1} = E_i - adjusted Lat"]'::jsonb, 'N_{i+1} = N_i + adjusted Lat; E_{i+1} = E_i + adjusted Dep', 'Northings accumulate adjusted latitudes and eastings accumulate adjusted departures. Using raw components leaves the loop open by the misclosure.', 'medium', 'c1000008-0000-0000-0000-000000000008', 'd597ed54-edfa-42b1-97b7-1064d9acc5f1', ARRAY['buildout','module-8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0830-0000-0000-0000-000000000020', 'Survey-grade horizontal coordinates in Texas are normally expressed on the Texas State Plane Coordinate System (NAD83).', 'true_false', '["True","False"]'::jsonb, 'True', 'Texas survey-grade work is typically tied to the Texas State Plane Coordinate System on NAD83, making coordinates compatible with GIS and recorded control. Remember to track grid vs. ground distances.', 'easy', 'c1000008-0000-0000-0000-000000000008', 'd597ed54-edfa-42b1-97b7-1064d9acc5f1', ARRAY['buildout','module-8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0830-0000-0000-0000-000000000021', 'The area-by-coordinates (shoelace) formula must be applied to which kind of traverse to give a correct area?', 'multiple_choice', '["A balanced (adjusted) closed traverse","An open traverse","A raw, unadjusted traverse","Any traverse, balanced or not"]'::jsonb, 'A balanced (adjusted) closed traverse', 'The shoelace method needs closed (balanced) coordinates; an unbalanced traverse includes the misclosure gap and yields a wrong area.', 'medium', 'c1000008-0000-0000-0000-000000000008', '1085aa13-7c9d-4929-84c8-bc9f7d50448b', ARRAY['buildout','module-8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0830-0000-0000-0000-000000000022', 'A parcel computes to 87,120 square feet. Its area in acres is:', 'numeric_input', '[]'::jsonb, '2.00', '1 acre = 43,560 sq ft, so 87,120 / 43,560 = 2.00 acres.', 'easy', 'c1000008-0000-0000-0000-000000000008', '1085aa13-7c9d-4929-84c8-bc9f7d50448b', ARRAY['buildout','module-8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0830-0000-0000-0000-000000000023', 'In the shoelace formula, traversing the corners clockwise instead of counterclockwise changes the computed area magnitude.', 'true_false', '["True","False"]'::jsonb, 'False', 'Reversing the direction only flips the sign of the summation, which the absolute value removes. The area magnitude is unaffected.', 'medium', 'c1000008-0000-0000-0000-000000000008', '1085aa13-7c9d-4929-84c8-bc9f7d50448b', ARRAY['buildout','module-8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
