INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee0860-0000-0000-0000-000000000001', 'A traverse course runs N {{ang:f0}} deg E for a horizontal distance of {{dist:f2}} ft. Compute the LATITUDE (north-south component) of this course in feet.', 'numeric_input', '[]'::jsonb, '0', 'Latitude = d cos(alpha) = {{dist:f2}} x cos({{ang:f0}} deg) = {{_answer}} ft north. (Its departure, d sin(alpha), would be {{dep:f2}} ft east.)', 'medium', 'c1000008-0000-0000-0000-000000000008', NULL, ARRAY['buildout','module-8','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee0850-0000-0000-0000-000000000001', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee0860-0000-0000-0000-000000000002', 'After summing all courses of a closed-loop traverse, the latitudes total {{sumLat:f3}} ft and the departures total {{sumDep:f3}} ft. Compute the LINEAR MISCLOSURE (ft).', 'numeric_input', '[]'::jsonb, '0', 'Linear misclosure is the hypotenuse of the latitude and departure misclosures: E = hypot({{sumLat:f3}}, {{sumDep:f3}}) = {{_answer}} ft.', 'medium', 'c1000008-0000-0000-0000-000000000008', NULL, ARRAY['buildout','module-8','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee0850-0000-0000-0000-000000000002', 0.002);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee0860-0000-0000-0000-000000000003', 'A closed-loop traverse has a perimeter of {{perim:f2}} ft and a linear misclosure of {{mis:f3}} ft. Express the relative precision as 1:N and report N (the denominator).', 'numeric_input', '[]'::jsonb, '0', 'Relative precision = perimeter / misclosure = {{perim:f2}} / {{mis:f3}} = {{_answer}}, so the ratio of closure is 1:{{_answer}}. A larger N is better.', 'medium', 'c1000008-0000-0000-0000-000000000008', NULL, ARRAY['buildout','module-8','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee0850-0000-0000-0000-000000000003', 2);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee0860-0000-0000-0000-000000000004', 'A closed traverse has a departure misclosure of {{misDep:f3}} ft over a perimeter of {{perim:f2}} ft. Using the compass (Bowditch) rule, compute the DEPARTURE CORRECTION (ft) applied to a course that is {{dist:f2}} ft long.', 'numeric_input', '[]'::jsonb, '0', 'The compass rule distributes the departure misclosure in proportion to course length: C_Dep = -E_D x (d/P) = -({{misDep:f3}}) x ({{dist:f2}}/{{perim:f2}}) = {{_answer}} ft. The negative sign removes the misclosure.', 'medium', 'c1000008-0000-0000-0000-000000000008', NULL, ARRAY['buildout','module-8','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee0850-0000-0000-0000-000000000004', 0.0005);
