-- 340_buildout_m8.sql (GENERATED) — fill empty lessons for "Traverse Computations"
-- Module c1000008-0000-0000-0000-000000000008. Namespaced by tag 'buildout' / created_by 'buildout:m8' so pre-existing rows are untouched.
BEGIN;
DELETE FROM question_bank     WHERE module_id='c1000008-0000-0000-0000-000000000008' AND 'buildout' = ANY(tags);
DELETE FROM flashcards        WHERE module_id='c1000008-0000-0000-0000-000000000008' AND 'buildout' = ANY(tags);
DELETE FROM problem_templates WHERE module_id='c1000008-0000-0000-0000-000000000008' AND created_by='buildout:m8';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['A traverse is a connected series of lines (courses) whose lengths and directions are measured to locate points and compute coordinates.','Open traverses have no closure check; closed-loop traverses return to the start; closed-connecting (link) traverses run between two points of known coordinates.','Only closed traverses (loop or link) allow misclosure to be computed and the work to be adjusted.','Texas boundary surveys are almost always run as closed traverses so that the description mathematically closes.']::text[], learning_objectives=ARRAY['Define a traverse and distinguish open, closed-loop, and closed-connecting (link) traverses.','Explain why only closed traverses provide a mathematical check on field measurements.','Identify which traverse type is appropriate for a given surveying task and the angle/coordinate conditions each must satisfy.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='4ea6aa56-31e3-4b33-a7e2-ab2dc6d7723e';
DELETE FROM lesson_blocks WHERE lesson_id='4ea6aa56-31e3-4b33-a7e2-ab2dc6d7723e';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['Plan station geometry first: intervisibility, strong angles, balanced course lengths, and stable monuments.','Carry direction by interior angles, deflection angles, or azimuths; close the horizon and repeat angles to catch blunders.','Measure every distance at least twice and apply instrument, atmospheric, and reflector corrections.','Record a clean, complete field note set: occupied, backsight, foresight, angles, distances, and HI.']::text[], learning_objectives=ARRAY['Describe the field workflow for establishing and observing a traverse with a total station.','Distinguish interior-angle, deflection-angle, and azimuth methods of carrying direction.','Apply good practice for station selection, monumentation, angle repetition, and distance verification to control error.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='c053d4ff-74a7-4594-a8d1-d0c401307e02';
DELETE FROM lesson_blocks WHERE lesson_id='c053d4ff-74a7-4594-a8d1-d0c401307e02';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Latitude = distance x cos(bearing) is the north (+) / south (-) component; departure = distance x sin(bearing) is the east (+) / west (-) component.','Use the bearing angle measured from the meridian (north-south line), and apply the sign of the quadrant.','Latitudes are + to the north and - to the south; departures are + to the east and - to the west.','Distance = hypot(latitude, departure) recovers the course length, a useful self-check.']::text[], learning_objectives=ARRAY['Define latitude (north-south component) and departure (east-west component) of a course.','Compute latitude and departure from a course''s bearing/azimuth and horizontal distance using lat = d*cos(bearing) and dep = d*sin(bearing).','Apply correct algebraic signs by quadrant and verify a course by recombining its components.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='61c4b9a9-e00e-4b80-99da-c15edf192c6e';
DELETE FROM lesson_blocks WHERE lesson_id='61c4b9a9-e00e-4b80-99da-c15edf192c6e';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['For a closed-loop traverse the latitudes should sum to zero and the departures should sum to zero; the residual sums are the misclosures in latitude and departure.','Linear misclosure = hypot(sum of latitudes, sum of departures).','Ratio (relative precision) = perimeter / linear misclosure, reported as 1:N where N = round(perimeter / misclosure).','A larger N (e.g., 1:10,000) is better; failing the required ratio signals a blunder or the need to re-observe.']::text[], learning_objectives=ARRAY['Compute the closure in latitude and departure for a closed traverse and combine them into the linear misclosure.','Express survey quality as the relative precision (ratio of closure) and interpret it as 1:N.','Compare a computed ratio of closure against typical standards and decide whether to adjust or re-observe.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='3dd698ce-6ccc-4a03-a8d7-f19a53f40a16';
DELETE FROM lesson_blocks WHERE lesson_id='3dd698ce-6ccc-4a03-a8d7-f19a53f40a16';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['The compass (Bowditch) rule assumes angles and distances are of comparable precision, so error is distributed in proportion to course length.','Correction to a course''s latitude = -E_L x (course length / perimeter); to its departure = -E_D x (course length / perimeter).','Longer courses receive proportionally larger corrections.','After adjustment the corrected latitudes and departures each sum to zero (loop) or to the known control difference (link).']::text[], learning_objectives=ARRAY['State the assumption behind the compass (Bowditch) rule and when it is appropriate.','Distribute the latitude and departure misclosures to each course in proportion to its length.','Compute the corrected latitudes and departures and confirm the adjusted sums close to zero.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='24eb9a48-b37f-4615-ac1b-db880aa3480c';
DELETE FROM lesson_blocks WHERE lesson_id='24eb9a48-b37f-4615-ac1b-db880aa3480c';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['The transit rule assumes angles are measured more precisely than distances, so error is distributed by the size of each course''s latitude/departure rather than its length.','Lat correction = -E_L x (|Lat_i| / sum|Lat|); Dep correction = -E_D x (|Dep_i| / sum|Dep|).','The transit rule changes the bearings less than the compass rule because corrections track the components.','Modern practice prefers the compass rule or least squares; the transit rule is a classical alternative for angle-dominant work.']::text[], learning_objectives=ARRAY['State the assumption behind the transit rule and contrast it with the compass rule.','Distribute the latitude and departure misclosures in proportion to the magnitudes of each course''s latitude and departure.','Choose between the transit and compass rules based on the relative precision of angle versus distance measurements.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='2e258399-f9ef-432f-a67c-b6e624269e55';
DELETE FROM lesson_blocks WHERE lesson_id='2e258399-f9ef-432f-a67c-b6e624269e55';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Coordinates are accumulated: N_{i+1} = N_i + adjusted Lat; E_{i+1} = E_i + adjusted Dep.','Start from a known or assumed coordinate at the point of beginning and add each course''s adjusted components in order.','After a closed loop the final computed coordinates must return exactly to the starting coordinates.','Texas survey-grade coordinates are usually expressed on the Texas State Plane Coordinate System (NAD83).']::text[], learning_objectives=ARRAY['Carry adjusted latitudes and departures forward to compute the coordinates of each traverse station.','Choose and apply a starting coordinate (assumed or state-plane) and accumulate components station to station.','Verify that the computed coordinates close back on the point of beginning.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='d597ed54-edfa-42b1-97b7-1064d9acc5f1';
DELETE FROM lesson_blocks WHERE lesson_id='d597ed54-edfa-42b1-97b7-1064d9acc5f1';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['The full workflow is: lat/dep -> misclosure and ratio -> adjust (compass/transit) -> coordinates -> area.','Area by coordinates (shoelace): A = (1/2)|sum of (x_i*y_{i+1} - x_{i+1}*y_i)|, using a balanced (closed) traverse.','Divide square feet by 43,560 to report area in acres.','Always carry the closure and coordinate checks through; an unbalanced traverse gives a wrong area.']::text[], learning_objectives=ARRAY['Integrate the full traverse workflow: compute latitudes/departures, find misclosure and ratio of closure, adjust, and compute coordinates and area.','Compute the area of a balanced traverse by the coordinate (shoelace) method.','Solve randomized practice problems that mirror licensure-exam computations.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='1085aa13-7c9d-4929-84c8-bc9f7d50448b';
DELETE FROM lesson_blocks WHERE lesson_id='1085aa13-7c9d-4929-84c8-bc9f7d50448b';
  'eeee0850-0000-0000-0000-000000000001', 'Latitude or departure of a course', 'Latitude or departure of a course', 'Traverse Computations — Course geometry', 'Latitude and departure', 'numeric_input', 'medium', 'A traverse course runs N {{ang:f0}} deg E for a horizontal distance of {{dist:f2}} ft. Compute the LATITUDE (north-south component) of this course in feet.', 'dist*cos(toRad(ang))', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"ang","type":"integer","min":15,"max":75},{"name":"dist","type":"float","min":150,"max":650,"decimals":2}]'::jsonb, '[{"name":"dep","formula":"dist*sin(toRad(ang))"}]'::jsonb, '[{"step_number":1,"title":"Latitude formula","formula":"Lat = d cos(alpha)","calculation_template":"{{dist:f2}} x cos({{ang:f0}} deg)"},{"step_number":2,"title":"Compute","result_template":"Latitude = {{_answer}} ft (north, positive)"}]'::jsonb, '{"method":"none"}'::jsonb, 'Latitude = d cos(alpha) = {{dist:f2}} x cos({{ang:f0}} deg) = {{_answer}} ft north. (Its departure, d sin(alpha), would be {{dep:f2}} ft east.)', 'c1000008-0000-0000-0000-000000000008', ARRAY['buildout','module-8','practice']::text[], true, 'buildout:m8');
  'eeee0850-0000-0000-0000-000000000002', 'Linear misclosure from latitude and departure errors', 'Linear misclosure from latitude and departure errors', 'Traverse Computations — Closure', 'Linear misclosure', 'numeric_input', 'medium', 'After summing all courses of a closed-loop traverse, the latitudes total {{sumLat:f3}} ft and the departures total {{sumDep:f3}} ft. Compute the LINEAR MISCLOSURE (ft).', 'hypot(sumLat, sumDep)', '{"decimals":3,"unit":"ft","tolerance":0.002}', '[{"name":"sumLat","type":"float","min":-0.18,"max":0.18,"decimals":3},{"name":"sumDep","type":"float","min":-0.18,"max":0.18,"decimals":3}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Misclosure formula","formula":"E = sqrt(sumLat^2 + sumDep^2)","calculation_template":"sqrt(({{sumLat:f3}})^2 + ({{sumDep:f3}})^2)"},{"step_number":2,"title":"Compute","result_template":"Linear misclosure = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Linear misclosure is the hypotenuse of the latitude and departure misclosures: E = hypot({{sumLat:f3}}, {{sumDep:f3}}) = {{_answer}} ft.', 'c1000008-0000-0000-0000-000000000008', ARRAY['buildout','module-8','practice']::text[], true, 'buildout:m8');
  'eeee0850-0000-0000-0000-000000000003', 'Relative precision (ratio of closure) denominator', 'Relative precision (ratio of closure) denominator', 'Traverse Computations — Closure', 'Ratio of closure', 'numeric_input', 'medium', 'A closed-loop traverse has a perimeter of {{perim:f2}} ft and a linear misclosure of {{mis:f3}} ft. Express the relative precision as 1:N and report N (the denominator).', 'round(perim/mis)', '{"decimals":0,"unit":"","tolerance":2}', '[{"name":"perim","type":"float","min":1200,"max":4000,"decimals":2},{"name":"mis","type":"float","min":0.08,"max":0.4,"decimals":3}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Ratio of closure","formula":"N = perimeter / misclosure","calculation_template":"{{perim:f2}} / {{mis:f3}}"},{"step_number":2,"title":"Report denominator","result_template":"Relative precision = 1:{{_answer}}"}]'::jsonb, '{"method":"none"}'::jsonb, 'Relative precision = perimeter / misclosure = {{perim:f2}} / {{mis:f3}} = {{_answer}}, so the ratio of closure is 1:{{_answer}}. A larger N is better.', 'c1000008-0000-0000-0000-000000000008', ARRAY['buildout','module-8','practice']::text[], true, 'buildout:m8');
  'eeee0850-0000-0000-0000-000000000004', 'Compass (Bowditch) rule departure correction for one course', 'Compass (Bowditch) rule departure correction for one course', 'Traverse Computations — Adjustment', 'Compass rule', 'numeric_input', 'medium', 'A closed traverse has a departure misclosure of {{misDep:f3}} ft over a perimeter of {{perim:f2}} ft. Using the compass (Bowditch) rule, compute the DEPARTURE CORRECTION (ft) applied to a course that is {{dist:f2}} ft long.', '-misDep*(dist/perim)', '{"decimals":4,"unit":"ft","tolerance":0.0005}', '[{"name":"misDep","type":"float","min":-0.16,"max":0.16,"decimals":3},{"name":"perim","type":"float","min":1000,"max":3000,"decimals":2},{"name":"dist","type":"float","min":150,"max":500,"decimals":2}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Compass rule correction","formula":"C_Dep = -E_D x (d / P)","calculation_template":"-({{misDep:f3}}) x ({{dist:f2}} / {{perim:f2}})"},{"step_number":2,"title":"Compute","result_template":"Departure correction = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The compass rule distributes the departure misclosure in proportion to course length: C_Dep = -E_D x (d/P) = -({{misDep:f3}}) x ({{dist:f2}}/{{perim:f2}}) = {{_answer}} ft. The negative sign removes the misclosure.', 'c1000008-0000-0000-0000-000000000008', ARRAY['buildout','module-8','practice']::text[], true, 'buildout:m8');
COMMIT;
SELECT 'm8 Traverse Computations: ' || (SELECT count(*) FROM lesson_blocks lb JOIN learning_lessons l ON l.id=lb.lesson_id WHERE l.module_id='c1000008-0000-0000-0000-000000000008') || ' blocks.' AS status;